INSERT INTO rule_book (section, title, content, order_num) VALUES
('每日游戏流程', '每日游戏流程', '一、白天自由行动（6:00-7:00）\r\n所有玩家选择两项自由行动。\r\n\r\n1.前往地点：选择一个地点进行探索，可以获得对应地点的信息（可能的资源信息取决于设施），防御值，NPC名单。同时可以选择使用非上锁的设施和地点NPC简单交互。\r\n在第一天开始时会在自己的家内醒来，会知道自己所在地点的信息。\r\n\r\n2.调查玩家：选择一玩家，知晓对方的自由行动，1/2概率获知阵营行动，无法调查潜行技能玩家。无法调查昨天隐藏行动玩家。\r\n\r\n3.生产：根据职业技能生产对应资源。\r\n\r\n4.使用特性：使用需要行动点的特性。\r\n\r\n5.使用职业技能：使用可能的职业技能。如果没有标有行动的技能不需要玩家行动就可以执行。\r\n\r\n6.隐藏：隐藏起自己，第二天不会被调查，也无法被私聊，无法成为统治者与密谋的行动目标。\r\n\r\n7.搬运：将物品从仓库移动到仓库或从仓库移动到自身，自身物品存放仓库不消耗行动点。\r\n\r\n二、主持人整理与反馈行动\r\n1.在8:00前结算"调查"、"特性"、"职业技能"、"调查玩家"。\r\n2.结算"生产"', 1);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('自由行动', '白天自由行动', '白天自由行动（6:00-7:00）\r\n所有玩家选择两项自由行动。\r\n\r\n1.前往地点：选择一个地点进行探索，可以获得对应地点的信息（可能的资源信息取决于设施），防御值，NPC名单。同时可以选择使用非上锁的设施和地点NPC简单交互。\r\n在第一天开始时会在自己的家内醒来，会知道自己所在地点的信息。\r\n\r\n2.调查玩家：选择一玩家，知晓对方的自由行动，1/2概率获知阵营行动，无法调查潜行技能玩家。无法调查昨天隐藏行动玩家。\r\n\r\n3.生产：根据职业技能生产对应资源。\r\n\r\n4.使用特性：使用需要行动点的特性。\r\n\r\n5.使用职业技能：使用可能的职业技能。如果没有标有行动的技能不需要玩家行动就可以执行。\r\n\r\n6.隐藏：隐藏起自己，第二天不会被调查，也无法被私聊，无法成为统治者与密谋的行动目标。\r\n\r\n7.搬运：将物品从仓库移动到仓库或从仓库移动到自身，自身物品存放仓库不消耗行动点。\r\n\r\n主持人整理与反馈行动\r\n1.在8:00前结算"调查"、"特性"、"职业技能"、"调查玩家"。\r\n2.结算"生产"', 2);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('自由讨论', '自由讨论', '自由讨论（5:00开始）\r\n在这个时间段开放地点语音频道，任何玩家可以自由选择频道进行语音讨论。\r\n\r\n自由讨论规则\r\n1.尽可能使用语音或者小群。\r\n2.如达成"协议"，需告知主持人，使得"协议"技能或使用协议书生效。\r\n3.禁止在此阶段进行任何的场外录音行为。', 3);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('协议', '协议', '协议——某些讨论的结果需要告知主持人\r\n\r\n1.加入阵营：一位玩家接受另一位所属阵营的玩家的邀请，并加入阵营群。这种情况非初始阵营玩家可能背叛。\r\n\r\n2.契约协议：两位或多位玩家在群聊或者kook频道都在场的的情况下，达成合作的意向与合作目标，并由其中一位玩家与女巫沟通（需要女巫在场并且同意），完成契约协议，或者使用协议书。如果违反协议内容，则会受到严苛的惩罚（由女巫或协议书使用者决定）。契约协议必须是一个完整的句子，不能是多条不相干的内容。每人每天最多签订一个契约。\r\n只有女巫（男巫）可以签订契约，若不使用协议书签订内容会被公开。但只公开内容不公开谁签订的契约。\r\n\r\n3.物品交换：两位或多位玩家交换物品。\r\n\r\n4.冒险者、反抗者、统治者阵营初始拥有1个协议书。\r\n\r\n什么不是协议？\r\n1.信息讨论：职业、拥有物品、行为、线索等等信息都不是协议。\r\n2.口头协作：两位或多位玩家达成合作的意向，临时加入阵营。', 4);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('夜间阶段', '夜间阶段', '夜间阶段（8:00到所有结算完毕）\r\n\r\n在该阶段，阵营玩家的行动与可能的暴力冲突根据其顺序结算，而无关的玩家可以继续进行自由讨论。\r\n\r\n1.玩家默认所在地点在自己家中，去往别的地点过夜需要告知主持人，不消耗行动点。\r\n2.主持人计算可能的冲突，并确认是否发生阵营行动与暴力冲突。\r\n3.结算阵营行动与暴力冲突。\r\n4.统治者公布第二天劳工名单。\r\n5.阵营告示可能的公开信息。\r\n6.主持人公开可以公开的夜间阶段总结信息。\r\n7.消耗与燃料食物。\r\n8.结算所有资源与设施情况。\r\n\r\n详细和补充规则见"夜间结算阶段规则"。', 5);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('群组与交流', '群组与交流', '一、群组\r\n1.四个阵营组建微信群组，可以在任意时间段自由讨论。如果在自由讨论阶段平民明确加入阵营并签订协议，通知主持人并拉入对应阵营群聊。\r\n2.所有的暴力冲突由主持人拉冲突参与者建小群，冲突结束后解散。\r\n3.所有人都在的微信群在游戏开始后禁止讨论。\r\n\r\n二、kook语音频道\r\n自由讨论阶段的语音频道，由玩家自主组织。\r\n\r\n三、kook公屏（集市）\r\n自由讨论阶段的文字频道，记住文字频道会留下记录，谨慎讨论。\r\n\r\n四、kook留言板\r\n在游戏中，统治者与冒险者可以在该频道发布信息，例如招募、资源征集等等。\r\n\r\n禁止一切形式的私自拉群行为。', 6);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('资源交换', '资源交换', '资源交换：核心原则\r\n\r\n1.自由自主的交换：玩家间交易遵旨自愿、自由、自主的原则。玩家可以在任何可能的交流场景达成资源交换的意图。所有交换双方是自愿、自由的。\r\n\r\n2.见证人：所有资源交换需要告知主持人，由主持人见证确保双方资源交换属实，只需要告知一下就可以。\r\n\r\n3.信息不对称：交换双方对资源真实价值、稀缺度和自身需求的信息不同。\r\n\r\n4.物资交换登记：交换任意一方需在网站页面上填写对应的物资数量，并发给主持人对应交易的kook截屏即为物资交换完成。\r\n\r\n参考\r\n- 摆摊：玩家可在KOOK公屏（集市）发布文字信息。发布[求购]急需医疗包，可用木材或情报交换。\r\n- 公开拍卖：统治者或拥有大量资源的玩家可发起资源出售，自由设定商品单与交易形式。', 7);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('资源移动', '资源移动', '一、玩家与玩家仓库资源转移\r\n在夜晚阶段自由交换，但是需告知主持人。\r\n\r\n二、玩家与仓库资源转移\r\n- 小镇内地点转移：一人一天不影响玩家行动的情况下50kg，跳过玩家行动300kg。\r\n- 岛屿地点转移：一人一天不影响玩家行动的情况下30kg，跳过玩家行动300kg。\r\n\r\n三、仓库与仓库资源转移\r\n- 小镇内地点：一人一天不影响玩家行动的情况下100kg，跳过玩家行动可以搬运500kg。不同的载具可以额外增加搬运量。\r\n- 岛屿地点：一人一天不影响玩家行动的情况下50kg。跳过玩家行动可以搬运300kg。不同的载具可以额外增加搬运量。\r\n\r\n四、生产资源原则\r\n- 自主原则：在网站行动选择哪个行动进行生产。\r\n- 强迫原则：如果因其他玩家强迫行动生产，被强迫方可以告知主持人，将生产资源添加到自己的仓库。', 8);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('战斗规则', '战斗规则', '一、计算总战力\r\n总战力 = 参战人数 + 武器威胁值之和 + 地点防御值（仅有守方）+ 技能/特性加成\r\n- 技能加成：格斗使用近战武器/射击使用远程武器 +1\r\n- 地点防御值：守方直接加在总战力里。攻方不加地点防御值。\r\n- 防弹衣/盾：不加战力，用于抵消受伤。物品效果查看物品栏。\r\n每人只能携带一件武器和两件防具参加战斗。\r\n\r\n二、最终攻击力判定\r\n- 攻方最终战力 = 攻方总战力 + 1d4\r\n- 守方最终战力 = 守方总战力 + 1d4\r\n- 差值 = 攻方最终 - 守方最终\r\n\r\n三、根据差值决定结果\r\n差值 ≥ 5：大胜——攻方无伤，守方1人死亡其余受伤\r\n差值 3-4：胜利——攻方无伤，守方1-2人重伤其余受伤\r\n差值 1-2：小胜——攻方无伤，守方全部受伤\r\n差值 0：僵持——双方各1人受伤\r\n差值 -1～-2：小败——攻方全部受伤，守方无伤\r\n差值 -3～-4：失败——攻方1-2人重伤其余受伤，守方无伤\r\n差值 ≤ -5：大败——攻方1人死亡其余受伤，守方无伤\r\n\r\n四、特殊规则\r\n- 在无远程武器的情况下，重伤和受伤标记会在手持近战武器的人员中随机给予。\r\n- 在有远程武器的情况下，重伤和受伤标记在全体人员中随机给予。\r\n- 在失败/胜利情况下1-2人重伤是看1d6骰子的出目，1-3为一人重伤，4-6为两人重伤。\r\n- 战败方掉落全体（每个人）的最高威胁值物品，受伤以及重伤玩家会被己方阵营带走。', 9);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('伤亡规则', '伤亡规则', '一、状态说明\r\n- 受伤：获得"受伤"标记（无法生产，格斗无效），可被医疗消除。\r\n- 重伤：获得"重伤"标记（无法行动，每夜阶段结束时若不急救则死亡）。急救消耗5医疗资源，将重伤转为受伤。\r\n- 死亡：直接移除角色。\r\n\r\n二、战斗事例\r\n示例1（1v1）\r\n攻方1人（步枪4），守方1人（手枪2，地点防御2）\r\n攻方总战力=1+4=5，守方=1+2+2=5\r\n掷骰：攻方3→8，守方1→6，D=2 → 小胜\r\n结果：守方受伤（倒地），攻方无伤。\r\n\r\n示例2（多人，大胜）\r\n攻方5人，武器威胁和=15，守方2人，武器威胁和=4，地点防御3\r\n攻方战力=5+15=20，守方=2+4+3=9\r\n攻方掷4→24，守方掷1→10，D=14 ≥5 → 大胜\r\n结果：守方1人死亡，另1人受伤。攻方无伤。', 10);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('夜间结算', '夜间结算阶段规则', '夜间结算阶段规则\r\n\r\n1.玩家默认所在地点在自己家中，去往别的地点过夜需要告知主持人，不消耗行动点。地点确定需要在决定晚上行动时告知主持人，不会额外提醒玩家是否更改过夜地点。\r\n\r\n2.主持人计算可能的冲突，并确认是否发生阵营行动与暴力冲突。\r\n\r\n3.结算阵营行动与暴力冲突\r\n- 夜间行动时生产建造搬运类优先结算，战斗与冲突最后结算。\r\n- 如果想要指定杀某个人就要在白天行动时使用调查明确对方的去向。如果是为了杀人去的某地点但是对方不在可以选择是否发起攻击，如果不攻击本行动点不会返还。\r\n- 如果发生A想杀→B想杀→C的情况，会判定为先结算B→C，再结算A→B。在此种情况下不会发生混战情况。\r\n- 如果A想杀→C，B想杀→C，会判定为A和B攻击C，AB是否进行战斗是在AB攻击C之后询问两方意见的。此时因为不在对应地点内，防守方战斗应不计地点防御值。\r\n\r\n4.统治者需要商议第二天劳工名单，并在夜晚结算之前给与主持人。\r\n\r\n5.阵营告示主持人可能要公开的信息。\r\n\r\n6.主持人公开可以公开的夜间阶段总结信息。例如死亡人数，但不会告知死亡地点和何人死亡、哪里被袭击等等。\r\n\r\n7.消耗与燃料食物\r\n- 每人每天的基础燃料消耗是15kg木材，如因其他技能或者天灾牌出现极寒情况，基础消耗调整为30kg木材。\r\n- 每人每天的基础食物消耗是2单位。\r\n\r\n8.结算所有资源与设施情况。', 11);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('天灾系统', '天灾系统', '一、天灾倒计时\r\n通过一个0到100的数字，作为"天灾"的进度，当任何游戏阶段到达100时，当天夜晚阶段的最后，进入游戏结算。同时这个进度会影响游戏中六面骰的概率。同时，通过一套天灾牌额外增加天灾点数，与各结局最终的存活难度。\r\n- 每天默认推进33点，第三天推进34点。\r\n- 主持人会抽取3张秘密天灾牌，由杀戮者选择1张触发。特色技能可以查看天灾牌。\r\n\r\n二、六面骰\r\n在游戏中有很多行为或者判定需要骰6面骰来决定是否成功或决定判断结果，例如射击、天灾使者特殊规则、特性中的随机奖励。', 12);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('天灾牌', '天灾牌', '1.低温侵袭\r\n某处墙体结冰，寒气渗入。本天所有燃料消耗增加20%，木材消耗量15kg→18kg。\r\n\r\n2.灾难蔓延\r\n增加5天暴雪持续时间。\r\n\r\n3.粮仓鼠患\r\n仓库中储存的粮食被老鼠啃食，损失10%的食物储备（向下取整）。\r\n\r\n4.燃料泄漏\r\n储油桶老化破裂，损失一处仓库的10%的燃料储备（优先扣除煤油/燃油）。\r\n\r\n5.工具锈蚀\r\n生产工具普遍老化。当天所有生产行动（渔猎、伐木、挖矿等）产量-20%。\r\n\r\n6.海水倒灌\r\n风暴潮淹没码头设施，沿海仓库的部分物资被冲走（损失10%），方舟受损10%。\r\n\r\n7.水源污染\r\n岛上淡水水源被动物尸体污染，所有玩家当天需额外消耗1升煤油（烧开水）或面临患病风险。\r\n\r\n8.信仰崩塌\r\n神父以及占卜师等精神领袖陷入自我怀疑，当天无法使用"布道"或"占星"技能。若第三天抽中不影响终局结算加成。\r\n\r\n9.燃料受潮\r\n露天堆放的木柴被雨淋湿。随机一个仓库或玩家损失30kg木材。\r\n\r\n10.逃役\r\n一名劳工趁夜色逃走了。统治者当天指定的劳工名单中，随机一人自动失效（不会劳作，也不会计入劳工）。主持人随机选择，不公开是谁。该玩家知道自己被逃役释放，当天正常进行行动。\r\n\r\n11.祭品\r\n有人在教堂门口发现一只被割喉的黑羊。第二天必定触发一张额外天灾牌（命运在积蓄）。', 13);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('NPC规则', 'NPC规则', '一、NPC基础规则\r\n- 会添加生产类NPC，NPC初始拥有不同阵营倾向。\r\n- NPC在不同的地点，玩家使用调查地点行动后知晓其地点存在的NPC列表。统治者开局知道所有NPC列表与其职业。\r\n- 对话行动可以与不同的NPC互动，获得不同的信息、效果，或者请求帮助。由主持人决定。\r\n\r\n二、态度说明\r\n- 喜好：该NPC会加入、帮助此阵营玩家。\r\n- 厌恶：该NPC会忽视、敌对此阵营玩家，不会提供帮助，反对被当做劳工等。\r\n- 忽视：该NPC对此阵营无感，不帮助也不会加入，如果被强迫，可能对寻找喜好阵营帮助。\r\n\r\n三、码头NPC\r\n艾琳娜·费舍尔（Elena Fischer）——渔民（女）\r\n每天独自出海捕鱼的渔妇，渴望离开这座被遗忘的岛屿。\r\n喜好：冒险者 | 厌恶：统治者 | 忽视：天灾使者、反抗者\r\n\r\n克拉拉·南丁格尔（Clara Nightingale）——渔民（女）\r\n一位家中贫困的普通渔民，只希望镇上保持平静。\r\n喜好：冒险者 | 厌恶：天灾使者 | 忽视：统治者、反抗者\r\n\r\n杰克·塔克（Jack Tucker）——水手（男）\r\n曾在商船当水手，船沉后困在岛上，做梦都想再上一次船。\r\n喜好：冒险者 | 厌恶：反抗者 | 忽视：天灾使者、统治者\r\n\r\n鲍勃·塔克——装卸工（男）\r\n一名一直在港口讨生活的搬运工。\r\n喜好：统治者 | 厌恶：反抗者 | 忽视：天灾使者、冒险者\r\n\r\n奥拉夫·斯滕（Olaf Sten）——渔民（男）\r\n满脸风霜的老水手，在海上讨生活三十年。\r\n喜好：冒险者 | 厌恶：反抗者 | 忽视：天灾使者、统治者\r\n\r\n四、伐木营地NPC\r\n托马斯·伍德（Thomas Wood）——伐木工（男）\r\n沉默寡言的伐木工，靠砍树和做木工为生，只求安稳度日。\r\n喜好：统治者 | 厌恶：反抗者 | 忽视：天灾使者、冒险者\r\n\r\n五、矿场NPC\r\n卡尔·铁锤（Carl Hammer）——矿工（男）\r\n脾气火爆的矿场工人，谁给好处就帮谁。\r\n喜好：统治者 | 厌恶：反抗者、天灾使者 | 忽视：冒险者\r\n\r\n维克多·斯通（Victor Stone）——矿工（男）\r\n体格强壮的矿工，相信权力才是活下去的依靠。\r\n喜好：统治者 | 厌恶：反抗者、天灾使者 | 忽视：冒险者\r\n\r\n六、市场NPC\r\n塞缪尔·格雷（Samuel Gray）——农户（男）\r\n善良而质朴的普通农户，乐于帮助他人。\r\n喜好：冒险者 | 厌恶：统治者 | 忽视：天灾使者、反抗者\r\n\r\n弗雷德里克·波特（Frederick Potter）——农户（男）\r\n性格孤僻，住在镇外，对别人的生死毫不在意。\r\n喜好：反抗者 | 厌恶：统治者 | 忽视：冒险者、天灾使者\r\n\r\n米玛·雷铁斯托——手工艺人（女）\r\n老实本分的手工艺人，喜欢待在自己的小屋偶尔出门。\r\n喜好：冒险者 | 厌恶：统治者 | 忽视：天灾使者、反抗者\r\n\r\n汉斯·施密特（Hans Schmidt）——工匠（男）\r\n什么都能修的工匠，从钟表到农具都难不倒他，只认工钱不认人。\r\n喜好：统治者 | 厌恶：天灾使者 | 忽视：冒险者、反抗者\r\n\r\n莉莉安·韦弗（Lilian Weaver）——工匠（女）\r\n精巧的粉刷匠，服务过很多客人，消息灵通。\r\n喜好：反抗者 | 厌恶：统治者 | 忽视：天灾使者、冒险者\r\n\r\n七、监狱NPC\r\n乔克·汤姆——民兵（男）\r\n初始就跟着统治者干的监狱看守，一名很忠诚的下属。只是他有点小小的缺点，但统治者们也只能视而不见。\r\n喜好：统治者 | 厌恶：天灾使者、反抗者 | 忽视：冒险者', 15);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('阵营机制', '阵营机制-统治者', '你拥有这个岛屿上的巨大话语权与暴力力量，但是你无法肆意妄为，因为在暗地里，反抗者与天灾使者正在积蓄力量，你必须给予足够的空间与利益来收买更多的人来对抗反抗者与天灾使者。天灾使者自翊正义但掩盖不了他们是混沌的人，只想着杀人。也许你也可以称呼他们另一个名字——杀戮者。\r\n\r\n一、阵营行动（统治者行动只要可以执行就不限次数）\r\n1.安排监管——统治者可以安排一位民兵或治安官执行白天行动，监管某个地点。在之后一天的自由行动阶段禁止其他玩家前往该地点，禁止其他玩家与该地点的设施或NPC交互。\r\n\r\n2.安排人员——统治者可以安排一位玩家或者喜好统治者的NPC执行自由行动，并强制共享自由行动的结果信息。玩家可以拒绝，这样做，统治者将有合理的理由进行审判。\r\n\r\n3.安排看守——统治者在夜晚阶段之前安排人员选择一个地点，通常是仓库或统治者所在地。玩家可以拒绝，这样做，统治者将有合理的理由进行审判。每位看守为一个地点防御值增加3，以及携带唯一武器威胁值的防御值。\r\n\r\n二、劳工机制\r\n夜间阶段开始之前（每天18:00前）统治者阵营讨论出一份由其他玩家组成的劳工名单，人数为0～10人（24人局0～6人，48人局0～10人）。\r\n\r\n成为劳工的玩家第二天白天行动将在矿场强制劳动，并添加"过劳"标记。该玩家的夜间行动可以进行，此时"过劳"标记已经生效。\r\n\r\n统治者可以安排劳工进行建设避难所行动。\r\n\r\n劳工类型基础值：\r\n- 普通劳工：基础值4，压榨后7\r\n- 职业劳工：基础值5，压榨后8\r\n\r\n统治者可以自由选择劳工的换班形式。一天一轮或不进行轮换。（但是要记住，食物与资源的生产仍然需要人手，而过度的压制会加强反抗者的势力，或是让所有阵营联合起来）\r\n\r\n三、过劳标记\r\n拥有过劳标记无法执行生产行动。拥有过劳标记在进行劳工的行动，投1d6投，判定为1则死亡。过劳标记在第三天消除。也就是说，必须隔一天进行劳作。\r\n\r\n四、压榨机制（统治者特权）\r\n- 次数限制：无所需特性情况下统治者每天最多可以对3名劳工使用压榨。\r\n- 效果：被压榨劳工的建造值按上表翻倍（4→7或5→8），但立即获得「受伤」标记。\r\n- 受伤后果：无法进行生产行动，格斗技能无效。\r\n- 策略提示：压榨可以快速推进建造值，但会增加医疗负担和激起反抗情绪。\r\n\r\n五、暴力机关\r\n统治者与其下属控制着仓库与几乎所有的火器，在冲突中占据绝对的优势。\r\n- 在游戏开始，每位统治者拥有一把韦伯利.38手枪与7发子弹。\r\n- 在游戏开始，仓库拥有大量的热武器。统治者可以自由分配武器，自由保存武器存放场景。\r\n\r\n六、公开宣传\r\n任何时候，统治者可以在频道公屏发布消息帖子。\r\n\r\n七、夜晚机制\r\n1.公开审判：统治者如果拥有对某个玩家的"合理"罪证信息（例如反抗统治者或天灾使者阵营，逃劳役等等）——可以选择在夜间阶段在集市召开公开审判。需要占用你们一人的夜间行动点召开，占用行动点的人为审判发起人。\r\n在审判期间，玩家可以在kook语音频道讨论。统治者可以选择性地收取民众的想法。或者选择公开投票的方式进行审判。\r\n审判结果最终由统治者决定，但如果不顺应民意可能会进一步失去民众的信任。\r\n\r\n审判结果：\r\n1.劳工——此玩家一直成为劳工。\r\n2.监禁——由统治者决定该玩家被囚禁在监狱，监禁时间无法进行任何自由行动。但需要保证他的基本存活。他的生存物资会从统治者仓库每日结算时自动扣除。\r\n3.死刑——该玩家死亡。（不顺应民意使用此种结果请务必三思）\r\n4.剥夺资产——该玩家的所有物品转移到统治者控制的仓库。\r\n5.无罪——也许是真的无辜又或者你们为了其他人而妥协了。\r\n\r\n2.额外行动：作为统治者夜晚出行虽然不完全安全但如果非要这么做的话也不是不行。使用手电筒在夜晚时间你可以执行白天回合的一个任意行动，或者尝试杀掉某个绊脚石。此环节无法寻找NPC进行对话，NPC在没有前置沟通的情况下会默认回家睡觉。\r\n\r\n八、下属\r\n统治者可以收买其他玩家，为自己做事。可以许诺资源、武器、阵营身份，或是权力。\r\n\r\n九、胜利条件\r\n目标1：扑灭反抗者与天灾使者，限制冒险者的发展，尽可能收买平民。\r\n目标2：建设避难所，在暴雪之前储备尽可能多的资源。\r\n目标3：让所有"自己人"和自己进入避难所。并且在暴雪将至阶段活下来。', 16);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('阵营机制', '阵营机制-反抗者', '你不是暴徒，你是被迫举枪的平民。\r\n当统治者的铁腕压得整座岛屿喘不过气——劳工被压榨、资源被垄断、异见者被关进牢房，你选择了另一条路：反抗。\r\n反抗者不是天生的叛逆者，而是那些受够了沉默代价的人。你们在暗处联络同胞，用破坏和密谋削弱统治者的控制，用舆论和施压点燃平民的怒火。你们不追求权力，只追求平等与自由。\r\n你们可以与除了统治者之外的所有阵营交流沟通，收集更多的平民力量。如果有必要潜入统治者进行情报刺探也是不错的选择。\r\n\r\n一、阵营行动（3选1）\r\n1.额外劳动：如果当天白天有行动的执行的生产，可以额外增加一半产出。\r\n\r\n2.暗中联络：选择1-3位玩家，由主持人统一代发一条秘密信息。什么都可以，不超过50字符即可（以WPS字符计算为准）。\r\n\r\n3.额外行动——作为反抗者你已经习惯在黑暗中行动，你不需要手电筒即可进行夜晚行动。在夜晚时间你可以执行白天回合的一个任意行动，或者尝试杀掉某个反抗革命的人。此环节无法寻找NPC进行对话，NPC在没有前置沟通的情况下会默认回家睡觉。\r\n\r\n初始资源：反叛者拥有猎枪×1，猎枪弹×2，猎弓×2，箭矢×4。\r\n\r\n二、向统治者施压\r\n在夜间阶段，任何玩家都可以团结其他玩家发起对统治者的施压，通过在公屏中发声的方式。而如果反抗者拥有合理的理由（通常是统治者的暴政或贪腐），则可以通过宣传来扩大施压的声音，以罢工或其他方式以此威胁。理由通常需要在自由行动阶段进行调查获得。\r\n通常，施压的目标有，"一个合理的劳工换班机制"、"扩大民兵"、"让资源由全体镇民管理"等等。\r\n在夜晚阶段开始前计算统一参加施压的人群，如果同意施压的人群超过玩家半数，统治者就必须妥协。\r\n记住，反抗者不应该直接参与施压，一旦身份暴露，就有被坑杀的可能。应当在自由讨论阶段合理的利用舆论。\r\n\r\n三、夜间回合（可以做也可以空过）\r\n1.进行密谋：袭击地点\r\n需要组织者确定袭击地点。可探索地点和统治者仓库（不显示在地图上）。\r\n- 每一位参与者增加一点成功率，参与者每一个拥有"潜行"技能增加1点成功率。每一位参与者佩戴唯一一把武器，增加武器对应"威慑点"的成功率。\r\n- 每个地点拥有基础防御值。统治者在目标地点的每一位玩家增加3点防御值，每一位玩家佩戴的唯一一把武器，增加武器对应"威慑点"的防御值。\r\n- 在夜间阶段结算密谋，比较成功率与防御值。\r\n  - 成功率大于防御值超过3点：密谋成功。\r\n  - 超过9点：行动成功，但行动暴露，所有参与成员名称公开。\r\n  - 不超过3点：失败。如果有，则需要放弃一把武器。\r\n  - 成功率小于防御值：行动失败。参与行动者可以选择受降或者暴力反抗。\r\n- 如果成功，玩家可以选择破坏该地点，或选择搜刮。破坏会直接烧毁该地点，在之后的游戏中，无法前往，无法使用该地点的设施，导致NPC死亡。搜刮则可以带走地点的所有资源。\r\n- 如果有民兵或治安官或看守里应外合，则减少3点防御值。\r\n\r\n2.暗杀统治者\r\n需要组织者确定统治者所在的地点。判定规则同密谋。\r\n- 如果成功率大于防御值超过3点：密谋成功，目标统治者死亡。\r\n- 如果超过9点：目标统治者死亡，但行动暴露，所有参与成员名称公开。\r\n- 如果统治者死亡，统治者阵营可以选择是否公开死亡消息。\r\n\r\n3.解救人员\r\n需要组织者确定被关押人员所在的地点。判定规则同密谋。\r\n- 潜行技能增加3点成功率（而非1点）。\r\n\r\n四、暴力革命\r\n在下列里程碑事件之中，完成任意其中三个，即可在当天或之后的阵营回合之中选择策划暴力革命。\r\n\r\n五、胜利条件\r\n目标1：推翻统治者，建立新的秩序。\r\n目标2：获得更多的平民。\r\n目标3：尽可能让所有人进入避难所。在暴雪将至阶段活下来。', 17);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('阵营机制', '阵营机制-冒险者', '在集体大会中，支持建设避难所的平民远高于建设大船，但是你依旧坚持这场灾难不会结束。而随着统治者暴力的加强，更多人会明白，建设避难所是一个糟糕的决定。\r\n建设方舟：一艘20世纪的帆船已经破旧不堪，但是仍然比归属于渔民与船队的渔船大得多，或许可以召集人手修复好帆船，在暴雨来临前让更多人逃离。\r\n\r\n一、阵营行动（5选1）\r\n1.额外调查：如果当天执行的调查地点，调查玩家。调查地点改为两个，调查玩家改为两名。\r\n\r\n2.额外劳动：如果当天有至少任意一个行动点执行的生产，可以额外增加一半产出。\r\n\r\n3.看守方舟——冒险者在白天行动阶段可以使用行动点作为方舟看守，在夜晚阶段为方舟建造地点增加对于武器与技能的防御值。\r\n\r\n4.方舟建设：在阵营回合可以进行方舟建造，在第三天开始时加入冒险者的人员都可以用自己所拥有的任意数量行动点进行方舟建造。\r\n\r\n初始资源：拥有猎弓2，12只箭，1只矛，一把手枪，4发手枪子弹。\r\n\r\n二、收集物资\r\n在游戏中，冒险者需要整合成员已有的资源，与其他阵营与玩家交换资源，生产资源，公开宣传以募集资源，直接冲突争夺资源，来获得建设方舟的材料与出航的必要物资。\r\n\r\n建设方舟的总共资源（50点载重的情况）：\r\n- 木材250吨\r\n- 金属制品100吨\r\n- 密封材料：沥青100kg\r\n- 发动机至少1个，最多3个\r\n- 螺旋桨2个\r\n- 发电机1个\r\n\r\n技能资源（出海需要的技能，为终局结算提供更多的优势）：\r\n航海、海洋导航、天气预报、渔猎\r\n\r\n三、建设与载重方案\r\n船身大小：冒险者可以选择不同的建设方案来匹配人数。\r\n初始已完成10吨木材，20吨金属制品资源的建设。（根据参与人数改变）\r\n\r\n以250吨木材的大小为基础设计，为50点载重。更小的船型会更加劣势。\r\n- 在完成50点基础载重之后，每增加10吨木材，5吨金属制品与5公斤密封材料，可以增加2点载重。\r\n- 每缺少10吨木材或5吨金属制品或5公斤密封材料，减少3点载重，百分之2.5方舟完成度。资源短缺是短板效应，按最低缺少计算。\r\n\r\n建设规则：\r\n加入冒险者任意一人可以在阵营行动时花费一行动点投入不超过单日最高数量的任意数量资源进行建造：\r\n每天投入最高为：木材30吨、金属制品20吨、密封材料20kg\r\n\r\n若材料不足需白天花费一人一行动点工作量推进：5吨木材、5吨铁制品建造进度、5kg密封材料\r\n\r\n四、出航准备\r\n- a.每1点载重一人，可以乘载一人\r\n- b.每1点载重，100单位食物\r\n- c.每1点载重，2吨燃料\r\n- d.每1点载重，500kg密封材料\r\n- e.每1点载重，2吨木材\r\n- f.医疗资源、武器等物品不计算重量。\r\n\r\n五、海上时间\r\n注意，某些危机事件可能增加航行天数。每多一天就需要额外抽取一张危机事件牌。\r\n- 1个发动机：8天航行时间\r\n- 2个发动机：6天航行时间\r\n- 3个发动机：4天航行时间\r\n- 在没有发动机出航或者只有一个发动机的时候，可以制造帆来辅助航行。在具有两个发动机时帆的作用消失。\r\n- 单帆：消耗100m绳索和80米帆布。收集好材料后需要一个人夜晚阵营回合建造帆，之后就可以使用。效果：提供移速加成。\r\n- 在没有发动机的时候，航行时间为10天。\r\n- 在只有一个发动机的时候，航行时间为7天。\r\n\r\n六、夜晚行动\r\n可以做可以不做。\r\n\r\n七、胜利条件\r\n目标1：选择与反抗者或统治者结盟，拉拢更多的平民。\r\n目标2：获得更多的资源建设方舟。\r\n目标3：在暴雪将至前出海，活下去。', 18);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('阵营机制', '阵营机制-天灾使者', '你们是天灾的使者，是净化这里的存在。这里已经是腐烂得无可救药了。统治者做着梦幻想统治永远存在却又看不起所有的居民；反抗者自以为正义实际上上位之后会不会变成统治者那些人也尤未可知；冒险者空有一腔热血但是方舟会去往哪里谁能知道。而且你们中有人知道的是大家……在这里的所有人——都是罪人。\r\n\r\n罪在哪里？\r\n眼睁睁看着邻居被送去审判，你闭了嘴，你是罪人。\r\n为了多领一份口粮，偷偷举报了别人，你是罪人。\r\n明知这座岛的规则是吃人的，你还是选择顺从，而不是站出来，你是罪人。\r\n统治者犯的罪是傲慢，反抗者犯的罪是自私，冒险者犯的罪是盲目，而普通人犯的罪是——沉默。\r\n所以，我们是执行者。所以是暴雪吗？是天灾吗？不！这是净化。\r\n\r\n一、阵营行动\r\n1.破坏：选择一个地点的一个设施，使其无法使用。如果目标地点被安排监管，无法破坏。\r\n\r\n2.额外调查：如果当天执行的调查地点，调查玩家。调查地点改为两个，调查玩家改为两名。\r\n\r\n3.诅咒：花费一件威胁值4以上的武器，选择2位玩家，知晓该玩家的阵营。该玩家被标记「诅咒」。\r\n\r\n二、阵营机制\r\n1.阻止胜利：天灾使者既可以是统治者的走狗，施加暴行，激化统治者与平民的矛盾，延缓建设的进度，也可以假扮反抗者或冒险者，分化各个阵营的力量或凝聚力。最终目的，都是增加玩家死亡，推进命运，减缓地下避难所与方舟的建设进度。尽可能让灾难杀死所有人。\r\n\r\n2.正义的潜伏：天灾使者可以以天灾使者的身份加入其他阵营，并使用两套阵营规则。仍然使用天灾使者的胜利条件。无法无视契约协议的惩罚。天灾使者知晓当天天灾牌的内容。\r\n\r\n3.进行密谋：袭击地点\r\n判定规则同反抗者密谋。\r\n- 如果成功，玩家可以选择破坏该地点，或选择搜刮。破坏会直接烧毁该地点，在之后的游戏中，无法前往，无法使用该地点的设施，导致地点所有NPC死亡。搜刮则可以带走地点的所有资源。\r\n\r\n4.制造恐怖：在夜晚阶段，需要组织者确定袭击地点或玩家。袭击玩家需要对方拥有诅咒，至少一位参与者参与。袭击地点，则至少需要两位参与者。\r\n- 制造恐怖的基础成功率取决于场上诅咒的数量和参与者的数量。\r\n- 每有一个诅咒（包括普通诅咒和瘟疫诅咒）成功概率+1\r\n- 每额外多一名参与者，成功概率+1\r\n- 使用1d6骰子投出数值+成功概率。结果大等于6既为成功。无视所有的防具，战力差距。\r\n- 在第一天时有平民玩家因为使者制造恐怖而死亡时，对方将受到天灾的感召。阵营身份变更为天灾使者继续进行游戏。（仅限一人）保留对方原有特性和技能。\r\n- 如果失败，参与者将暴露身份。身份被目标地点所属玩家与目标玩家知晓。不会告知你的具体身份是天灾使者。只会告知玩家袭击了对方，没有成功。同时所有被诅咒标记玩家在公屏公开。\r\n- 如果成功，如果目标拥有诅咒，目标玩家死亡。如果是目标地点，由参与者选择破坏1d6数量的资源品名或设施。\r\n- 如果目标死亡，统治者阵营可以选择是否公开死亡消息。\r\n\r\n5.神契：当命运之轮到达100，触发暴雪将至。杀戮者共有三个神启身份对应其他玩家的特性，名为：瘟疫、战争和饥荒。如果剩下的杀戮玩家只剩下一位他变为死亡骑士，特性更改为死亡骑士。\r\n\r\n三、胜利条件\r\n目标1：隐藏在人群中，蛊惑平民，制造信息迷雾，破坏其他阵营的策略。\r\n目标2：阻止方舟与避难所的建设，破坏资源与仓库。\r\n目标3：让暴雪更快降临。', 19);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('阵营机制', '阵营机制-平民', '一、阵营机制\r\n1.加入阵营：平民玩家可以自由选择加入反抗者或是冒险者的阵营，或是成为统治者的下属。\r\n\r\n2.口头契约：玩家与玩家之间可以口头协议加入阵营，但无法使用阵营行动与机制。但在这种情况下，平民玩家可以通过口头契约加入多个阵营。\r\n\r\n3.自组织：平民玩家可以尝试形成团体，为一个目标行动。\r\n\r\n4.加入阵营与背叛：平民玩家可以通过各种方式，加入某个阵营。加入对应阵营的玩家可以使用阵营机制与阵营行动。可以在行动阶段告知主持人决定背叛，在夜晚阶段由主持人结束背叛阵营事件，并且踢出阵营群聊。无法再使用阵营机制与阵营行动。\r\n\r\n二、胜利条件\r\n目标1：你也要死吗？不，请活下去，直到最后。\r\n\r\n三、初始人数配置（给主持人）\r\n统治者：4 | 反抗者：4 | 冒险者：3 | 天灾使者：3', 20);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('方舟建造', '方舟建造', '一、方舟建设\r\n在阵营回合可以进行方舟建造，在第三天开始时加入冒险者的人员都可以用自己所拥有的任意数量行动点进行方舟建造。\r\n\r\n二、收集物资\r\n在游戏中，冒险者需要整合成员已有的资源，与其他阵营与玩家交换资源，生产资源，公开宣传以募集资源，直接冲突争夺资源，来获得建设方舟的材料与出航的必要物资。\r\n\r\n建设方舟的总共资源（50点载重的情况）：\r\n- 木材250吨\r\n- 金属制品100吨\r\n- 密封材料：沥青100kg\r\n- 发动机至少1个，最多3个\r\n- 螺旋桨2个\r\n- 发电机1个\r\n\r\n技能资源（出海需要的技能，为终局结算提供更多的优势）：\r\n航海、海洋导航、天气预报、渔猎\r\n\r\n三、建设与载重方案\r\n船身大小：冒险者可以选择不同的建设方案来匹配人数。\r\n初始已完成10吨木材，20吨金属制品资源的建设。（根据参与人数改变）\r\n\r\n以250吨木材的大小为基础设计，为50点载重。更小的船型会更加劣势。\r\n- 在完成50点基础载重之后，每增加10吨木材，5吨金属制品与5公斤密封材料，可以增加2点载重。\r\n- 每缺少10吨木材或5吨金属制品或5公斤密封材料，减少3点载重，百分之2.5方舟完成度。资源短缺是短板效应，按最低缺少计算。\r\n\r\n建设规则：\r\n加入冒险者任意一人可以在阵营行动时花费一行动点投入不超过单日最高数量的任意数量资源进行建造：\r\n每天投入最高为：木材30吨、金属制品20吨、密封材料20kg\r\n\r\n若材料不足需白天花费一人一行动点工作量推进：5吨木材、5吨铁制品建造进度、5kg密封材料\r\n\r\n四、出航准备\r\n- a.每1点载重一人，可以乘载一人\r\n- b.每1点载重，100单位食物\r\n- c.每1点载重，2吨燃料\r\n- d.每1点载重，500kg密封材料\r\n- e.每1点载重，2吨木材\r\n- f.医疗资源、武器等物品不计算重量。\r\n\r\n五、海上时间\r\n注意，某些危机事件可能增加航行天数。每多一天就需要额外抽取一张危机事件牌。\r\n- 1个发动机：8天航行时间\r\n- 2个发动机：6天航行时间\r\n- 3个发动机：4天航行时间\r\n- 在没有发动机出航或者只有一个发动机的时候，可以制造帆来辅助航行。在具有两个发动机时帆的作用消失。\r\n- 单帆：消耗100m绳索和80米帆布。收集好材料后需要一个人夜晚阵营回合建造帆，之后就可以使用。效果：提供移速加成。\r\n- 在没有发动机的时候，航行时间为10天。\r\n- 在只有一个发动机的时候，航行时间为7天。', 21);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('技能表', '技能表', '一、战斗类\r\n格斗——在密谋、暴力冲突中，如果装备近距离武器增加威胁值。如果调查玩家，可以选择在夜晚阶段骰d6，寻找攻击机会（初始12 30/3, 50/4, 80/5），成功可以发起小规模冲突。多人调查可以袭击。\r\n\r\n射击——在密谋、暴力冲突中，如果装备远距离武器增加威胁值。如果调查玩家，可以选择在夜晚阶段骰d6，寻找攻击机会（初始12 30/3, 50/4, 80/5），成功可以发起小规模冲突。多人调查可以袭击。\r\n\r\n二、生产类（在白天行动阶段使用生产行动，如需设施需要对应设施完好）\r\n- 捕鱼：在码头使用渔船设施，获得食物10单位。\r\n- 食物生产：使用牲畜设施，获得食物15单位。\r\n- 伐木：使用电锯20吨木材，否则5吨。\r\n- 挖掘：使用电钻20吨石料，否则5吨。\r\n- 手工艺：工具制备单制作一件或至多3件材料、物品或武器。\r\n  制作列表：复合盾（3kg金属制品+3kg木材）、副鱼叉/矛（5kg金属制品+5kg木材）、规制箭矢（3kg木材+3kg金属制品3支）\r\n- 木石工艺：使用木板蒸汽箱，将30吨原木转化为20吨木板，消耗10吨燃料/使用切石机，将20吨石料转化为15米石墙。\r\n- 射击狩猎：需要远程武器（无需子弹或弓箭），5kg肉。\r\n\r\n三、功能类（在白天阶段联系主持人使用，或者其他特殊方式使用）\r\n- 潜行（被动）：为谋略增加成功率，无法被调查。\r\n- 启蒙：每天白天行动时一次，消耗一盒粉笔和2支铅笔，选择除自己之外最多2名玩家，使其临时学会一项基础技能（从以下列表中选：急救、潜行、格斗、捕鱼、伐木、挖矿），从第一天夜晚回合生效持续到第二天白天回合结束。若该玩家已经拥有该技能则增产50%。\r\n- 布道：每天白天行动时一次，选择最多为3人，被布道的玩家在下一个行动中生产增加一半（渔猎、伐木、挖矿）/或者最多为3位玩家消除诅咒（被诅咒的玩家没有任何征兆，这是一个纯预判的技能效果）。\r\n- 急救：花费5医疗资源，将"重伤"改为"受伤"标记。\r\n- 医疗：每天白天行动时一次，选择一位或至多5位"受伤"标记的玩家，目标消除"受伤"标记。每个花费3医疗资源，选择一位或多位过劳标记的玩家，消除过劳标记。每个花费2医疗资源。（可以混合）\r\n- 通灵：需消耗10根蜡烛和2升酒精举行仪式。每天白天行动时一次，与一位已死亡玩家建立临时私信交流，死亡玩家需要尽可能告知死前所有信息（由主持人保底提供信息）同时你有1/2概率会获得对方的技能。\r\n- 协议契约：为一位或多位玩家建立协议契约。可以指定违反协议的惩罚内容。\r\n- 潜水：每天白天行动时可以进行一次，在码头使用，由主持人投d6决定结果：1-5食物8单位，6沉船遗物（随机一件较高价值物品，由主持人决定，如医疗包、维修工具包、旧手枪+弹药、信号枪等）。\r\n- 维修：每天可使用一次，修复一个被破坏的设施，花费5维修资源。\r\n- 搬运（被动）：搬运量永远是其他职业的两倍。\r\n\r\n四、特殊类（特殊技能需要自由行动中的技能行动执行）\r\n- 海洋导航：为方舟终局结算提供好的结局倾向，可以查看今日所有的天灾牌。\r\n- 偷盗：选择一位玩家，获得对方的秘密资源信息，选择一件物品获得。需要投掷1d6+1检定在5以上即可获得对方一件物品。\r\n- 天气预测：你通过科学的手段发现异常的暴雪天气的来临，可以查看今日所有的天灾牌。为所有终局结算提供好的结局倾向。\r\n- 占星：为避难所终局结算提供好的结局倾向。在全局游戏中你可以将一张天灾牌撕毁（不生效），或让一张危机事件牌撕毁（不生效）。\r\n- 烘焙：需要10单位的食物和15kg木材可以制作一份便当。便当：当天额外获得1白天行动点，每人每天最多使用1次。\r\n- 巡逻：夜晚行动，若你目前是非阵营玩家想使用该技能而不想加入阵营可以用第二天的一个行动补觉（体现为第二天的一个自由行动将变为其他且只能睡觉）使用该技能。选择一个地点，当晚该地点内非统治者阵营玩家的夜晚行动成功率-30%，巡夜人知晓其行动类型。需要巡夜人当天未处于"劳工"或"过劳"状态。', 22);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('标记系统', '标记系统', '一、状态标记\r\n- 过劳：拥有过劳标记无法执行生产行动、调查玩家和隐匿。拥有过劳标记在当天夜晚行动和第二天进行需要行动点的生产行动时，投1d6骰子，判定为1则死亡。过劳标记在第三天消除。也就是说，必须隔一天进行劳作。5瓶朗姆酒可以消除过劳状态。\r\n- 受伤：无法进行生产行动，格斗技能无效。\r\n- 重伤（致命伤害）：在夜晚阶段如果没有被急救，将死亡。\r\n- 束缚：无法执行自由行动和夜间行动，除非束缚被解除。\r\n- 虚弱：无法生产，格斗、射击技能无效，第三天消除，或者喝酒。\r\n- 诅咒标记：只有天灾使者知晓效果。\r\n\r\n二、其他\r\n- 赐福1：每次战斗，免疫第一次被命中的攻击骰。默认为1威胁，可以与近战武器堆叠。', 23);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('终局结算', '进入避难所与方舟', '一、进入避难所\r\n在第三天夜晚环节前往避难所。并被避难所的所属玩家或阵营同意进入。\r\n在进入避难所时除统治者之外的玩家需从个人仓库选择5-10种，不超过5000kg重量的物品直接转移到避难所仓库作为进入的投诚。若投诚之后还有剩余物资，选择1-2件可以偷偷带入避难所。\r\n在反抗者夺取避难所控制权时，可以自由设定要不要把玩家所有资产充公。\r\n\r\n二、登上方舟\r\n在任意一天夜晚阶段用行动点前往方舟。并被方舟的所属冒险者阵营同意登上方舟。所有除武器装备之外所有资源将自动转移到冒险者阵营仓库（不能超出方舟载重）。\r\n\r\n三、特别注意\r\n- 避难所不能在天灾值到达100之前启动关门机制。\r\n- 方舟可以在天灾值到达100之前开船离开，如果天灾值到达100强制登船离开。开船行为不可逆，不可以开船之后掉头回到小岛。\r\n- 避难所和方舟的关门与开船机制都在每天的阵营行动和夜晚回合之后。（半夜关门和半夜走）每天最后一个行动结算。', 24);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('终局结算', '避难所结局结算', '避难所结局结算\r\n\r\n第一阶段：暴雪持续时间判定\r\n暴雪不会立刻结束，其持续时间决定了避难所需要承受的总考验时长。\r\n- 基础持续时间：90天。\r\n- 杀戮者干预：每位存活的杀戮者（天灾使者）玩家，将额外触发一张危机事件牌。\r\n- 天灾诅咒：每一个进入避难所玩家所拥有的诅咒标记，会额外抽取一张危机事件牌。\r\n- 暴雪持续时间（D）= 90 +（已触发天灾牌数量）+（天灾使者进入避难所人数×5）。\r\n\r\n第二阶段：避难所基础资源需要\r\n固定每人10日消耗：\r\n- 食物：每人需要25000大卡。\r\n- 燃料：每人需要100kg木材或50公斤煤炭或等价热量。\r\n- 照明与设备：固定消耗5升煤油。\r\n- 人力需求：进入避难所的人数×（暴雪持续天数/10）\r\n\r\n危机处理：\r\n抽取最终天数/10天的危机事件牌。（如是小数按向下取整计算）\r\n例如天灾最终持续天数为95天。95÷10=9.5，向下取整为9。\r\n混入了一个天灾使者额外加1危机事件牌。最终抽取9+1=10张危机事件牌。\r\n牌堆构成：危机事件牌 + 来自技能的希望牌（拥有占星和天气预测的玩家各提供1张正面事件牌加入牌堆）。\r\n\r\n第三阶段：终局资源结算与生存检定\r\n结算完所有危机事件牌后。通过三种资源确定最终存活人数。\r\n最终幸存人数 = 初始进入人数 × 生存系数（S）\r\n\r\n生存系数（S）由以下几个关键资源的充足率决定，每项系数初始为1.0，根据短缺程度扣减：\r\n\r\n1.食物充足率（F）\r\nF = 实际食物储备总量（大卡）/（总人口 × 2单位食物/天 × D）\r\n影响：若F < 1.0，则S = S × F。例如：食物只够70%的需求，则幸存人数直接打7折。\r\n\r\n2.燃料充足率（H）\r\nH = 实际燃料储备总热量/（总人口 × 每日基础燃料热量 × D）\r\n若H < 1.0，则S = S ×（H^0.5）。（平方根意味着燃料短缺的影响稍缓，但会导致冻伤和疾病）。燃料严重短缺时（例如H<0.5），主持人可额外判定直接冻死一定比例玩家（如5%-10%）。\r\n\r\n3.医疗与秩序系数（M）\r\n- 医疗资源储备：每10份医疗资源，使M增加0.05（上限+0.2）。\r\n- "患病"标记：结算时，每存在一个此标记，使M减少0.02。"患病"标记来源于危机事件牌。\r\n- 特殊职业或特性：拥有布道、医疗、占星的玩家并存活，可以为群体提供0.1的士气加成。\r\n- S = S ×（1.0 + M）。M可以是正数或负数。\r\n\r\n最终结局与阵营胜利关联：\r\n【新纪元的基石】（对应S ≥ 0.8）\r\n反抗者：由其主导，则达成人民之声与地下黎明结局。\r\n统治者：由其主导，则达成地下黎明结局。无阵营：地下黎明。\r\n\r\n【惨白的黎明】（对应0.5 ≤ S < 0.8）\r\n反抗者：由其主导，则达成人民之声结局。\r\n统治者：由其主导，则达成王的废墟结局。无阵营：挽歌结局。\r\n\r\n【地狱归来的幸存者】（对应0.2 ≤ S < 0.5）\r\n统治者：由其主导，则达成王的废墟结局。\r\n杀戮者：达成天灾的馈赠结局。\r\n\r\n【寂静的坟墓】（对应S < 0.2）\r\n杀戮者：达成天灾的馈赠结局。', 25);
INSERT INTO rule_book (section, title, content, order_num) VALUES
('终局结算', '方舟结局结算', '方舟结局结算\r\n当冒险者阵营成功建造可以出航的方舟，并在暴雪来临前启航，游戏进入此结算流程。这是一个基于资源、技能、事件检定的叙事性终局。\r\n\r\n第一阶段：启航准备\r\n结算基础：\r\n- 最终登船玩家名单、各玩家携带的私人资源。\r\n- 方舟公共储备：食物（大卡）、燃料、医疗资源、工具、备用船材（木材、金属制品）等。\r\n\r\n第二阶段：航行阶段事件检定\r\n- 固定消耗：每人每天消耗2单位食物。\r\n- 燃料：根据发动机数量、航行天数和航速计算。如果公共储备无法满足消耗可以拆除一部分船只（减少船体完整度5%来补充一吨燃料）补足。\r\n- 抽取并结算航行事件：\r\n  牌堆构成：危机事件牌 + 来自技能的希望牌（拥有天气预测、海洋导航技能的玩家各提供1张正面事件牌加入牌堆）。\r\n  抽取数量：杀戮者干预——每位成功登船的杀戮者玩家，额外触发一张危机事件牌。危机事件抽取：航行天数×1+船上每个"诅咒"标记一张。\r\n- 阶段结算：如果船体完整度降至0%，或食物完全耗尽，则航行失败，或燃料无法完成动态增加的航行天数，直接进入【出海死亡】结局。\r\n\r\n第三阶段：登陆检定与最终结局\r\n判定完所有事件牌。最终生存系数（S）计算：\r\n- 基础生存率：S = 1.0\r\n- 资源修正：食物F = 实际食物储备总量（大卡）/（总人口 × 2500大卡/天 × D）。若F < 1，则S = S × F。\r\n- 船体完整度修正：H = 船体完整度（%） / 100。若H < 1，则S = S × H。\r\n- 技能与秩序修正（M）：正面——每拥有一项关键技能（渔猎、海洋导航、天气预测）+0.05；负面——每一个"患病"标记使M减少0.02。"患病"标记会在危机事件牌中产生。\r\n- 最终S = S_initial ×（资源修正）×（1 + M），S值范围通常在0到1.5之间。\r\n\r\n最终结局判定：\r\n\r\n【诺亚方舟】\r\n条件：S ≥ 1.1。船体完整度>70%，资源充足，士气高昂。\r\n"桅杆指向崭新的海岸线。方舟几乎完好，储备尚丰。人们相互扶持着踏上了坚实的土地。"\r\n结局：远航者\r\n\r\n【出海逃生——幸存者】\r\n条件：0.5 ≤ S < 1.1。船体有一定损坏，资源紧张，减不减员按各种物资储备结算。\r\n"船勉强冲上沙滩，龙骨发出最后的呻吟。每个人都精疲力尽。回首望去，故乡已沉入海平线之下。但前方，是陌生的、充满未知的土地。你们活下来了。"\r\n结局：黎明之前\r\n\r\n【出海死亡——深海长眠】（失败结局）\r\n条件：S < 0.5或船沉、资源耗尽。\r\n"……指南针失灵，风暴永无止息。最后一片帆被撕碎，船舱开始进水。在绝望的呼喊与冰冷的海水之间，方舟的梦想连同它的乘客，一同沉入永恒的寂静。"\r\n结局：深海长眠', 26);
